queries.sparql:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?interface_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasUser_Interface ?child ; p:hasStreaming_Service ?parent . } GROUP BY ?child }
  ?child p:interface_type ?interface_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streaming_Services } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?interface_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasUser_Interface ?child ; p:hasStreaming_Service ?parent . } GROUP BY ?child }
  ?child p:interface_type ?interface_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streaming_Services } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?interface_type WHERE {
  ?streaming_service_user_interface a :Streaming_Service_User_Interface .
  ?user_interface a :User_Interface .
  ?streaming_service_user_interface p:hasUser_Interface ?user_interface .
  ?streaming_service a :Streaming_Services .
  ?streaming_service_user_interface p:hasStreaming_Service ?streaming_service .
  ?streaming_service p:name ?name .
  ?user_interface p:interface_type ?interface_type .
} }
}
